package co.edu.elecciones.controller; import co.edu.elecciones.commons.dto.ApiResponse; import co.edu.elecciones.dto.Responses.DashboardAdmin; import co.edu.elecciones.repository.*; import org.springframework.web.bind.annotation.*;
@RestController @RequestMapping("/api/v1/admin/dashboard") public class DashboardController { private final ElectionRepository e; private final UserRepository u; private final PartyRepository p; private final CandidateRepository c; private final AuditEventRepository a; public DashboardController(ElectionRepository e,UserRepository u,PartyRepository p,CandidateRepository c,AuditEventRepository a){this.e=e;this.u=u;this.p=p;this.c=c;this.a=a;} @GetMapping public ApiResponse<DashboardAdmin> get(){ return ApiResponse.ok("OK",new DashboardAdmin(e.count(),u.count(),p.count(),c.count(),a.count())); }}
